   133→          </StyledHeading>
   134→          <Body type="span">
   135→            <Skeleton width="35%" />
   136→          </Body>
   137→          <Description>
   138→            <Skeleton />
   139→          </Description>
   140→          <Body type="span">
   141→            <Skeleton width="25%" height="23px" style={{ marginTop: 24 }} />
