import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';

import { Breadcrumb } from './Breadcrumb';

const meta = {
  component: Breadcrumb,
  tags: ['ai-generated', 'needs-work'],
} satisfies Meta<typeof Breadcrumb>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  args: {
    items: [{ label: 'Home', path: '/' }, { label: 'All restaurants', path: '/categories' }],
  },
  play: async ({ canvas }) => {
    await expect(canvas.getByText('home')).toBeVisible();
    await expect(canvas.getByText('all restaurants')).toBeVisible();
  },
};

export const WithCurrentPage: Story = {
  args: {
    items: [
      { label: 'Home', path: '/' },
      { label: 'All restaurants', path: '/categories' },
      { label: 'Italian' },
    ],
  },
};

export const SingleItem: Story = {
  args: {
    items: [{ label: 'Home', path: '/' }],
  },
};

import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';

import { Modal } from './Modal';
import { Body } from '../typography';

const meta = {
  component: Modal,
  tags: ['ai-generated', 'needs-work'],
  args: {
    isOpen: true,
    onClose: () => {},
  },
} satisfies Meta<typeof Modal>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Open: Story = {
  args: {
    children: <Body>Modal content goes here.</Body>,
  },
  play: async ({ canvasElement }) => {
    const doc = canvasElement.ownerDocument;
    const modal = doc.querySelector('[data-testid="modal"]');
    await expect(modal).toBeTruthy();
  },
};

export const WithLongContent: Story = {
  args: {
    children: (
      <div>
        <Body>First paragraph of modal content.</Body>
        <Body>Second paragraph with more detail.</Body>
        <Body>Third paragraph closing the message.</Body>
      </div>
    ),
  },
};

export const Closed: Story = {
  args: {
    isOpen: false,
    children: <Body>This should not be visible.</Body>,
  },
};

